import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { sendOtp, verifyOtp, checkRiderApproval } from "../services/api";
import { useAuth } from "../contexts/AuthContext";
import {
  Box,
  Button,
  Container,
  TextField,
  Typography,
  Alert,
  CircularProgress,
} from "@mui/material";

export default function RiderLogin() {
  const [mobile, setMobile] = useState("");
  const [otp, setOtp] = useState("");
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState({ type: "", text: "" });
  const navigate = useNavigate();
  const { login } = useAuth();

  // âś… Regex for 10-digit mobile numbers
  const isValidMobile = (num) => /^[0-9]{10}$/.test(num);

  // đźš€ Send OTP
  const handleSendOtp = async () => {
    setMessage({ type: "", text: "" });
    if (!mobile || !isValidMobile(mobile)) {
      setMessage({ type: "error", text: "Enter a valid 10-digit mobile number" });
      return;
    }
    try {
      setLoading(true);

      // âś… Check approval (for rider mode)
      const approvalRes = await checkRiderApproval(mobile);
      if (!approvalRes.data?.approved) {
        setMessage({
          type: "info",
          text: "Your account is still waiting for admin approval.",
        });
        setLoading(false);
        return;
      }

      const res = await sendOtp(mobile, "rider");
      if (res.data.success) {
        setStep(2);
        setMessage({ type: "success", text: "OTP sent! Check your mobile." });
      } else {
        setMessage({ type: "error", text: res.data.message || "Failed to send OTP" });
      }
    } catch (err) {
      const errorMessage =
        err.response?.data?.message || "Server error while sending OTP";
      setMessage({ type: "error", text: errorMessage });
    } finally {
      setLoading(false);
    }
  };

  // đźš€ Verify OTP
  const handleVerifyOtp = async () => {
    setMessage({ type: "", text: "" });
    if (!otp || otp.length !== 6) {
      setMessage({ type: "error", text: "Enter the 6-digit OTP" });
      return;
    }
    try {
      setLoading(true);
      const res = await verifyOtp(mobile, otp, "rider");

      if (res.data.success) {
        // âś… Save all roles
        login({
          token: res.data.token,
          roles: res.data.user?.roles || ["rider"],
          user: res.data.user,
        });

        setMessage({
          type: "success",
          text: "Login successful! Redirecting...",
        });

        // Decide where to go: if driver role exists, go to driver dashboard, else rider dashboard
        if (res.data.user?.roles?.includes("driver")) {
          setTimeout(() => navigate("/driver-dashboard"), 700);
        } else {
          setTimeout(() => navigate("/rider-dashboard"), 700);
        }
      } else {
        setMessage({ type: "error", text: res.data.message || "OTP verification failed" });
      }
    } catch (err) {
      const errorMessage =
        err.response?.data?.message || "Server error while verifying OTP";
      setMessage({ type: "error", text: errorMessage });
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="xs">
      <Box
        sx={{
          mt: 8,
          p: 4,
          border: "1px solid #ccc",
          borderRadius: 2,
          textAlign: "center",
        }}
      >
        <Typography variant="h5" gutterBottom>
          Login
        </Typography>

        {message.text && (
          <Alert severity={message.type} sx={{ mb: 2 }}>
            {message.text}
          </Alert>
        )}

        {step === 1 && (
          <>
            <TextField
              fullWidth
              label="Mobile Number"
              value={mobile}
              onChange={(e) => setMobile(e.target.value)}
              margin="normal"
              inputProps={{ maxLength: 10 }}
            />
            <Button
              fullWidth
              variant="contained"
              sx={{ mt: 2 }}
              onClick={handleSendOtp}
              disabled={loading}
            >
              {loading ? <CircularProgress size={22} /> : "Send OTP"}
            </Button>
          </>
        )}

        {step === 2 && (
          <>
            <TextField
              fullWidth
              label="Enter OTP"
              value={otp}
              onChange={(e) => setOtp(e.target.value)}
              margin="normal"
              inputProps={{ maxLength: 6 }}
            />
            <Button
              fullWidth
              variant="contained"
              sx={{ mt: 2 }}
              onClick={handleVerifyOtp}
              disabled={loading}
            >
              {loading ? <CircularProgress size={22} /> : "Verify OTP"}
            </Button>
          </>
        )}

        <Typography sx={{ mt: 2 }}>
          Donâ€™t have an account?{" "}
          <Button onClick={() => navigate("/rider-register")}>Sign Up</Button>
        </Typography>
      </Box>
    </Container>
  );
}
